    if (typeof category !== 'string' || typeof fileName !== 'string' || typeof data !== 'string') {
        throw new TypeError('Invalid arguments: category, fileName, and data must be strings');
    }

    // Prevent null byte poisoning (CWE-626)
    if (category.includes('\0') || fileName.includes('\0')) {
        throw new Error('Invalid path: contains null bytes');
    }

    const baseDir = '/tmp/resources';
    const absoluteBaseDir = path.resolve(baseDir);

    // Construct the file path using path.join
    const targetPath = path.join(baseDir, category, fileName);
    const absoluteTargetPath = path.resolve(targetPath);

    // Prevent Path Traversal (CWE-22) by ensuring the resolved path is strictly within the base directory
    if (!absoluteTargetPath.startsWith(absoluteBaseDir + path.sep)) {
        throw new Error('Security Error: Path traversal attempt detected');
    }

    // Ensure the target directory exists before writing the file
    const targetDir = path.dirname(absoluteTargetPath);
    if (!fs.existsSync(targetDir)) {
        fs.mkdirSync(targetDir, { recursive: true });
    }

    // Save the serialized data content into the corresponding snapshot file
    fs.writeFileSync(absoluteTargetPath, data);
}

